import java.io.*;class Main{static int[] solve(int[] nums,int k){int n=nums.length,m=n-k+1;int[] w=new int[m];int sum=0;for(int i=0;i<n;i++){sum+=nums[i];if(i>=k)sum-=nums[i-k];if(i>=k-1)w[i-k+1]=sum;}int[] left=new int[m],right=new int[m];int best=0;for(int i=0;i<m;i++){if(w[i]>w[best])best=i;left[i]=best;}best=m-1;for(int i=m-1;i>=0;i--){if(w[i]>=w[best])best=i;right[i]=best;}int[] ans=new int[]{0,0,0};int bestSum=-1;for(int mid=k;mid<m-k;mid++){int a=left[mid-k],c=right[mid+k];int total=w[a]+w[mid]+w[c];int[] cand=new int[]{a,mid,c};if(total>bestSum||total==bestSum&&less(cand,ans)){bestSum=total;ans=cand;}}return ans;}static boolean less(int[] a,int[] b){for(int i=0;i<a.length;i++)if(a[i]!=b[i])return a[i]<b[i];return false;}static String fmt(int[] a){return "["+a[0]+","+a[1]+","+a[2]+"]";}public static void main(String[] a)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[] d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int n=Integer.parseInt(d[idx++]),k=Integer.parseInt(d[idx++]);int[] nums=new int[n];for(int i=0;i<n;i++)nums[i]=Integer.parseInt(d[idx++]);if(tc>0)out.append("\n\n");out.append(fmt(solve(nums,k)));}System.out.print(out);}}
